/* ROBUST JSON PARSER */
// Iteramos sobre todos los items que entran
for (const item of items) {

  // 1. Buscamos dónde está el contenido (A veces 'output', 'text', 'content' o todo el json)
  const rawData = item.json.output || item.json.text || item.json.content;

  // CASO A: ¡Ya es un Objeto JSON! (La IA lo parseó sola)
  // Si ya es un objeto y no es nulo, no hay nada que limpiar. Salimos.
  if (typeof rawData === 'object' && rawData !== null) {
      continue; 
  }

  // CASO B: Es Texto (String) con posible Markdown
  if (typeof rawData === 'string') {
      try {
          // Limpiamos los bloques de código ```json ... ```
          let cleanText = rawData.replace(/```json/g, '').replace(/```/g, '').trim();

          // Intentamos convertir ese texto limpio a Objeto
          const parsedObject = JSON.parse(cleanText);

          // ¡ÉXITO! Fusionamos el objeto limpio con el item original
          Object.assign(item.json, parsedObject);

      } catch (error) {
          // Si falla, al menos guardamos el texto limpio como 'output' para que no se pierda
          item.json.output = rawData; 
      }
  }
}

return items;

// Iteramos sobre cada item que llega
for (const item of items) {

  // 1. BUSQUEDA EXHAUSTIVA DE LA IMAGEN
  // Buscamos en body, en query, o en la raíz (por si acaso)
  const imageField = item.json.body?.image || item.json.query?.image || item.json.image;

  if (imageField) {
    // 2. Limpiamos el encabezado "data:image/png;base64," si viene
    const parts = imageField.split('base64,');
    const rawBase64 = parts.length > 1 ? parts[1] : parts[0];

    // 3. Creamos el objeto Binario
    item.binary = {
      image: {
        data: rawBase64,
        mimeType: 'image/png',
        fileExtension: 'png',
        fileName: 'captura_pantalla.png'
      }
    };
    // Flag para saber que SÍ se procesó
    item.json.debug_image_processed = true; 
  } else {
    // Flag para saber que NO se encontró imagen
    item.json.debug_image_processed = false;
    item.json.debug_error = "No se encontró campo 'image' en body ni query";
  }
}

return items;

// Parsear y formatear pregunta de verificación
for (const item of items) {
  let content = item.json.choices?.[0]?.message?.content || item.json.message?.content || item.json.content || '{}';

  // Limpiar bloques de código markdown
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  try {
    const parsed = JSON.parse(content);
    item.json = parsed;
  } catch (error) {
    console.error('Error parsing verification question:', error);
    item.json = { error: 'Failed to parse JSON', raw: content };
  }
}
return items;

// Obtener los datos directamente del nodo anterior (Switch1)
const data = $input.first().json.body;
// Función simple para generar ID único sin depender de librerías externas
function generateUUID() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
}
return {
    json: {
        new_token: generateUUID(), 
        email: data.email,
        password: data.password,
        name: data.name,
        created_at: new Date().toISOString()
    }
}

// 1. Obtener datos del Webhook
const inputPass = $("Webhook").first().json.body.password;
const targetSubject = $("Webhook").first().json.body.subject || "MATEMATICA";

// 2. Obtener datos del usuario (desde Get row(s) in sheet3)
const foundUsers = $input.all();

if (foundUsers.length === 0) {
    return { json: { success: false, error: "Usuario no encontrado" } };
}

const dbUser = foundUsers[0].json;

// 3. Validar y enviar datos a la siguiente etapa
if (inputPass == dbUser.password) {
    return {
        json: {
            success: true,
            user_id: dbUser.token, // Este es el ID que usaremos para filtrar
            name: dbUser.nombre,
            subject: targetSubject // Enviamos la materia para el filtro
        }
    };
} else {
    return { json: { success: false, error: "Contraseña incorrecta" } };
}

/* MATH AGENT CLEANER */
// Este código extrae el JSON válido ignorando el texto de "Razonamiento" previo.

for (const item of items) {
  // 1. Obtener la salida cruda del agente
  let rawText = item.json.output || item.json.text || "";

  // 2. Buscar dónde empieza y termina el JSON real
  const firstCurly = rawText.indexOf('{');
  const lastCurly = rawText.lastIndexOf('}');

  if (firstCurly !== -1 && lastCurly !== -1) {
    // Extraer solo la parte que parece JSON
    const potentialJson = rawText.substring(firstCurly, lastCurly + 1);

    try {
      // 3. Intentar parsear y limpiar
      const parsedElem = JSON.parse(potentialJson);

      // Reemplazar todo el item con el JSON limpio
      item.json = parsedElem;

      // Asegurar que exista la estructura esperada
      if (!item.json.questions && item.json.quiz) {
         item.json.questions = item.json.quiz; // Estandarizar
      }

    } catch (error) {
      item.json.error_parsing = error.message;
      item.json.raw_output = rawText;
    }
  } else {
    // Si no hay corchetes, dejarlo pasar (pero probablemente falle)
    item.json.error_no_json_found = true;
  }
}

return items;

// Obtener todos los datos que llegaron
const allData = $input.all();
const firstItem = allData[0].json;

let completedSessions = [];
let targetUserId, targetSubject, userName;

// DETECCIÓN INTELIGENTE: ¿Llegaron sesiones de la hoja o datos del usuario?
// Si existe la columna 'session_number |', son datos de la hoja.
if (firstItem['session_number |'] !== undefined) {
    // CASO A: El alumno TIENE progreso registrado
    targetUserId = firstItem['user_id ']; // Ojo con el espacio
    targetSubject = firstItem['subject '];

    // Intentamos recuperar el nombre del nodo de Login de forma segura
    try {
        userName = $("Code in JavaScript3").first().json.name;
    } catch (e) {
        userName = "Estudiante"; // Fallback si no viene del login directo
    }

    // Extraemos la lista de números
    completedSessions = allData.map(row => {
        return parseInt(row.json['session_number |']);
    }).filter(Number.isInteger);

} else {
    // CASO B: El alumno NO tiene progreso (o es nuevo)
    // Tomamos los datos del input original que pasó gracias a "Always Output Data"
    targetUserId = firstItem.user_id || firstItem.body?.user_id;
    targetSubject = firstItem.subject || firstItem.body?.subject || "MATEMATICA";
    userName = firstItem.name || "Estudiante";
    completedSessions = [];
}

// Calcular próxima sesión
let nextSession = 1;
const sorted = completedSessions.sort((a, b) => a - b);

for (let i = 1; i <= 50; i++) {
    if (!sorted.includes(i)) {
        nextSession = i;
        break;
    }
}

return {
    json: {
        success: true,
        user_id: targetUserId,
        name: userName,
        subject: targetSubject,
        next_session: nextSession,
        total_completed: sorted.length,
        completed_list: sorted
    }
};

